 53→import { parseArgs } from "node:util";
 54→var options = {
 55→  query: { type: "string", short: "q" },
 56→  file: { type: "string", short: "f" },
 57→  host: { type: "string" },
 58→  port: { type: "string" },
 59→  user: { type: "string", short: "u" },
 60→  password: { type: "string" },
 61→  database: { type: "string", short: "d" },
 62→  secure: { type: "boolean", short: "s", default: false },
 63→  format: { type: "string", short: "F" },
 64→  time: { type: "boolean", short: "t", default: false },
 65→  verbose: { type: "boolean", short: "v", default: false },
 66→  help: { type: "boolean", default: false },
 67→  version: { type: "boolean", default: false }
 68→};
 69→function parseCliArgs(args) {
 70→  const { values } = parseArgs({
 71→    options,
 72→    strict: true,
 73→    args: args ?? process.argv.slice(2)
 74→  });
 75→  return values;
 76→}
 77→function printHelp() {
 78→  console.log(`chcli — ClickHouse CLI
 79→
 80→Usage: chcli [options]
 81→
 82→Query input (one of):
 83→  -q, --query <sql>       Inline SQL query
 84→  -f, --file <path>       Path to .sql file
 85→  (stdin)                 Pipe query via stdin
 86→
 87→Connection:
 88→      --host <host>       ClickHouse host (env: CLICKHOUSE_HOST, default: localhost)
 89→      --port <port>       HTTP port (env: CLICKHOUSE_PORT, default: 8123)
 90→  -u, --user <user>       Username (env: CLICKHOUSE_USER or CLICKHOUSE_USERNAME, default: default)
 91→      --password <pass>   Password (env: CLICKHOUSE_PASSWORD, default: "")
 92→  -d, --database <db>     Database (env: CLICKHOUSE_DATABASE or CLICKHOUSE_DB, default: default)
 93→  -s, --secure            Use HTTPS (env: CLICKHOUSE_SECURE)
 94→
 95→  CLICKHOUSE_URL is also supported (e.g. https://host:8443) and will be
 96→  used for host, port, secure, and password if the individual env vars
 97→  are not set.
 98→
 99→Output:
100→  -F, --format <fmt>      Output format (json, jsonl, csv, tsv, pretty, vertical, markdown, sql)
101→  -t, --time              Print execution time to stderr
102→  -v, --verbose           Print query metadata to stderr
103→
104→Other:
105→      --help              Show help text
106→      --version           Print version`);
107→}
108→function printVersion() {
109→  const pkg = require_package();
110→  console.log(`chcli ${pkg.version}`);
111→}
