113→// src/client.ts
114→import { createClient } from "@clickhouse/client";
115→function parseClickHouseUrl(raw) {
116→  const url = new URL(raw);
117→  return {
118→    host: url.hostname,
119→    port: url.port || (url.protocol === "https:" ? "8443" : "8123"),
120→    secure: url.protocol === "https:",
121→    password: url.password || undefined
122→  };
123→}
124→function resolveConnectionConfig(config) {
125→  const parsed = process.env.CLICKHOUSE_URL ? parseClickHouseUrl(process.env.CLICKHOUSE_URL) : undefined;
126→  const host = config.host || process.env.CLICKHOUSE_HOST || parsed?.host || "localhost";
127→  const port = config.port || process.env.CLICKHOUSE_PORT || parsed?.port || "8123";
128→  const secure = config.secure || process.env.CLICKHOUSE_SECURE === "true" || (parsed?.secure ?? false);
129→  const protocol = secure ? "https" : "http";
130→  return {
131→    url: `${protocol}://${host}:${port}`,
132→    username: config.user || process.env.CLICKHOUSE_USER || process.env.CLICKHOUSE_USERNAME || "default",
133→    password: config.password || process.env.CLICKHOUSE_PASSWORD || parsed?.password || "",
134→    database: config.database || process.env.CLICKHOUSE_DATABASE || process.env.CLICKHOUSE_DB || "default"
135→  };
136→}
137→function createClickHouseClient(config) {
138→  return createClient(resolveConnectionConfig(config));
139→}
