141→// src/query.ts
142→import { readFile } from "node:fs/promises";
143→async function resolveQuery(config) {
144→  if (config.query) {
145→    return config.query;
146→  }
147→  if (config.file) {
148→    return await readFile(config.file, "utf8");
149→  }
150→  if (!process.stdin.isTTY) {
151→    return await readStdin();
152→  }
153→  printHelp();
154→  process.exit(1);
155→}
156→async function readStdin() {
157→  const chunks = [];
158→  for await (const chunk of process.stdin) {
159→    chunks.push(typeof chunk === "string" ? Buffer.from(chunk) : chunk);
160→  }
161→  return Buffer.concat(chunks).toString("utf8");
162→}
