164→// src/format.ts
165→var FORMAT_ALIASES = {
166→  json: "JSON",
167→  jsonl: "JSONEachRow",
168→  ndjson: "JSONEachRow",
169→  jsoncompact: "JSONCompact",
170→  csv: "CSVWithNames",
171→  tsv: "TabSeparatedWithNames",
172→  pretty: "PrettyCompactMonoBlock",
173→  vertical: "Vertical",
174→  markdown: "Markdown",
175→  sql: "SQLInsert"
176→};
177→function resolveFormat(userFormat) {
178→  if (userFormat) {
179→    return FORMAT_ALIASES[userFormat.toLowerCase()] ?? userFormat;
180→  }
181→  return process.stdout.isTTY ? "PrettyCompactMonoBlock" : "TabSeparatedWithNames";
182→}
