184→// src/run.ts
185→var DATA_QUERY_PATTERN = /^\s*(SELECT|SHOW|DESCRIBE|DESC|EXPLAIN|EXISTS|WITH)\b/i;
186→async function run() {
187→  const config = parseCliArgs();
188→  if (config.help) {
189→    printHelp();
190→    return;
191→  }
192→  if (config.version) {
193→    printVersion();
194→    return;
195→  }
196→  const query = await resolveQuery(config);
197→  const format = resolveFormat(config.format);
198→  const client = createClickHouseClient(config);
199→  try {
200→    const start = performance.now();
201→    if (DATA_QUERY_PATTERN.test(query)) {
202→      const result = await client.query({
203→        query,
204→        format
205→      });
206→      const text = await result.text();
207→      if (text) {
208→        process.stdout.write(text);
209→      }
210→    } else {
211→      await client.command({ query });
212→    }
213→    const elapsed = performance.now() - start;
214→    if (config.time) {
215→      console.error(`Elapsed: ${(elapsed / 1000).toFixed(3)}s`);
216→    }
217→    if (config.verbose) {
218→      console.error(`Format: ${format}`);
219→      console.error(`Elapsed: ${(elapsed / 1000).toFixed(3)}s`);
220→    }
221→  } finally {
222→    await client.close();
223→  }
224→}
225→
226→// index.ts
227→run().catch((err) => {
228→  console.error(err.message ?? err);
229→  process.exit(1);
