// src/cli.ts
import { parseArgs } from "node:util";
var options = {
  query: { type: "string", short: "q" },
  file: { type: "string", short: "f" },
  host: { type: "string" },
  port: { type: "string" },
  user: { type: "string", short: "u" },
  password: { type: "string" },
  database: { type: "string", short: "d" },
  secure: { type: "boolean", short: "s", default: false },
  format: { type: "string", short: "F" },
  time: { type: "boolean", short: "t", default: false },
  verbose: { type: "boolean", short: "v", default: false },
  help: { type: "boolean", default: false },
  version: { type: "boolean", default: false }
};
function parseCliArgs(args) {
  const { values } = parseArgs({
    options,
    strict: true,
    args: args ?? process.argv.slice(2)
  });
  return values;
}
function printHelp() {
  console.log(`chcli — ClickHouse CLI

Usage: chcli [options]

Query input (one of):
  -q, --query <sql>       Inline SQL query
  -f, --file <path>       Path to .sql file
  (stdin)                 Pipe query via stdin

Connection:
      --host <host>       ClickHouse host (env: CLICKHOUSE_HOST, default: localhost)
      --port <port>       HTTP port (env: CLICKHOUSE_PORT, default: 8123)
  -u, --user <user>       Username (env: CLICKHOUSE_USER or CLICKHOUSE_USERNAME, default: default)
      --password <pass>   Password (env: CLICKHOUSE_PASSWORD, default: "")
  -d, --database <db>     Database (env: CLICKHOUSE_DATABASE or CLICKHOUSE_DB, default: default)
  -s, --secure            Use HTTPS (env: CLICKHOUSE_SECURE)

  CLICKHOUSE_URL is also supported (e.g. https://host:8443) and will be
  used for host, port, secure, and password if the individual env vars
  are not set.

Output:
  -F, --format <fmt>      Output format (json, jsonl, csv, tsv, pretty, vertical, markdown, sql)
  -t, --time              Print execution time to stderr
  -v, --verbose           Print query metadata to stderr

Other:
      --help              Show help text
      --version           Print version`);
}
function printVersion() {
  const pkg = require_package();
  console.log(`chcli ${pkg.version}`);
}

// src/client.ts
import { createClient } from "@clickhouse/client";
function parseClickHouseUrl(raw) {
  const url = new URL(raw);
  return {
    host: url.hostname,
    port: url.port || (url.protocol === "https:" ? "8443" : "8123"),
    secure: url.protocol === "https:",
    password: url.password || undefined
  };
}
function resolveConnectionConfig(config) {
  const parsed = process.env.CLICKHOUSE_URL ? parseClickHouseUrl(process.env.CLICKHOUSE_URL) : undefined;
  const host = config.host || process.env.CLICKHOUSE_HOST || parsed?.host || "localhost";
  const port = config.port || process.env.CLICKHOUSE_PORT || parsed?.port || "8123";
  const secure = config.secure || process.env.CLICKHOUSE_SECURE === "true" || (parsed?.secure ?? false);
  const protocol = secure ? "https" : "http";
  return {
    url: `${protocol}://${host}:${port}`,
    username: config.user || process.env.CLICKHOUSE_USER || process.env.CLICKHOUSE_USERNAME || "default",
    password: config.password || process.env.CLICKHOUSE_PASSWORD || parsed?.password || "",
    database: config.database || process.env.CLICKHOUSE_DATABASE || process.env.CLICKHOUSE_DB || "default"
  };
}
function createClickHouseClient(config) {
  return createClient(resolveConnectionConfig(config));
}

// src/query.ts
import { readFile } from "node:fs/promises";
async function resolveQuery(config) {
  if (config.query) {
    return config.query;
  }
  if (config.file) {
    return await readFile(config.file, "utf8");
  }
  if (!process.stdin.isTTY) {
    return await readStdin();
  }
  printHelp();
  process.exit(1);
}
async function readStdin() {
  const chunks = [];
  for await (const chunk of process.stdin) {
    chunks.push(typeof chunk === "string" ? Buffer.from(chunk) : chunk);
  }
  return Buffer.concat(chunks).toString("utf8");
}

// src/format.ts
var FORMAT_ALIASES = {
  json: "JSON",
  jsonl: "JSONEachRow",
  ndjson: "JSONEachRow",
  jsoncompact: "JSONCompact",
  csv: "CSVWithNames",
  tsv: "TabSeparatedWithNames",
  pretty: "PrettyCompactMonoBlock",
  vertical: "Vertical",
  markdown: "Markdown",
  sql: "SQLInsert"
};
function resolveFormat(userFormat) {
  if (userFormat) {
    return FORMAT_ALIASES[userFormat.toLowerCase()] ?? userFormat;
  }
  return process.stdout.isTTY ? "PrettyCompactMonoBlock" : "TabSeparatedWithNames";
}

// src/run.ts
var DATA_QUERY_PATTERN = /^\s*(SELECT|SHOW|DESCRIBE|DESC|EXPLAIN|EXISTS|WITH)\b/i;
async function run() {
  const config = parseCliArgs();
  if (config.help) {
    printHelp();
    return;
  }
  if (config.version) {
    printVersion();
    return;
  }
  const query = await resolveQuery(config);
  const format = resolveFormat(config.format);
  const client = createClickHouseClient(config);
  try {
    const start = performance.now();
    if (DATA_QUERY_PATTERN.test(query)) {
      const result = await client.query({
        query,
        format
      });
      const text = await result.text();
      if (text) {
        process.stdout.write(text);
      }
    } else {
      await client.command({ query });
    }
    const elapsed = performance.now() - start;
    if (config.time) {
      console.error(`Elapsed: ${(elapsed / 1000).toFixed(3)}s`);
    }
    if (config.verbose) {
      console.error(`Format: ${format}`);
      console.error(`Elapsed: ${(elapsed / 1000).toFixed(3)}s`);
    }
  } finally {
    await client.close();
  }
}

// index.ts
run().catch((err) => {
  console.error(err.message ?? err);
  process.exit(1);
});
